mapper.select:
select
    login_time as loginTime,
    login_status as loginStatus,
    agent_account as agentAccount,
    agent_id as agentId,
    agent_type as agentType,
    login_ip as loginIp,
    ip_control_id as ipControlId,
    ip_attribution as ipAttribution,
    login_device as loginDevice,
    device_number as deviceNumber,
    device_control_id as deviceControlId,
    login_address as loginAddress,
    device_version as deviceVersion,
    agent_label_id as agentLabelId,
    remark as remark
    from agent_login_record
where 1 = 1

    AND site_code =#{siteCode}


    AND agent_type = #{vo.agentType}


    AND agent_account = #{vo.agentAccount}


    AND login_ip = #{vo.loginIp}


    AND ip_attribution = #{vo.ipAttribution}


    AND login_device IN

        #{value}



    AND device_number = #{vo.deviceNumber}


    AND login_status = #{vo.loginStatus}


    AND login_time  >=  #{vo.startTime}


    AND login_time  <=  #{vo.endTime}




        ORDER BY loginTime asc


        ORDER BY loginTime desc



        order by login_time desc , login_status asc, login_ip desc

select
    count(0)
from agent_login_record
where 1 = 1

    AND site_code =#{siteCode}


    AND agent_type = #{vo.agentType}


    AND agent_account = #{vo.agentAccount}


    AND login_ip = #{vo.loginIp}


    AND ip_attribution = #{vo.ipAttribution}


    AND login_device IN

        #{value}



    AND device_number = #{vo.deviceNumber}


    AND login_status = #{vo.loginStatus}


    AND login_time  >=  #{vo.startTime}


    AND login_time  <=  #{vo.endTime}
